import{_ as t,c as i,o as e,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"常見問題: OAuth 認證與模型排查 | Antigravity Auth","description":"了解 Antigravity Auth 插件的常見問題與解決方案。涵蓋 OAuth 認證失敗排查、模型未找到錯誤處理、插件相容性配置等實用指南，幫助你快速定位並解決使用中遇到的各類問題。","frontmatter":{"title":"常見問題: OAuth 認證與模型排查 | Antigravity Auth","sidebarTitle":"認證失敗怎麼辦","subtitle":"常見問題: OAuth 認證與模型排查","description":"了解 Antigravity Auth 插件的常見問題與解決方案。涵蓋 OAuth 認證失敗排查、模型未找到錯誤處理、插件相容性配置等實用指南，幫助你快速定位並解決使用中遇到的各類問題。","order":4},"headers":[],"relativePath":"zh-tw/NoeFabris/opencode-antigravity-auth/faq/index.md","filePath":"zh-tw/NoeFabris/opencode-antigravity-auth/faq/index.md"}'),o={name:"zh-tw/NoeFabris/opencode-antigravity-auth/faq/index.md"};function r(n,a,d,h,u,s){return e(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h1><p>本章節收錄了使用 Antigravity Auth 插件時最常遇到的問題和解決方案。無論是 OAuth 認證失敗、模型請求報錯，還是插件相容性問題，這裡都有對應的排查指南。</p><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前請確保</p><ul><li>✅ 已完成 <a href="./../start/quick-install/">快速安裝</a> 並成功添加帳戶</li><li>✅ 已完成 <a href="./../start/first-auth-login/">首次認證</a> 並理解 OAuth 流程</li></ul></div><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><p>根據你遇到的問題類型，選擇對應的排查指南：</p><h3 id="_1-oauth-認證失敗排查" tabindex="-1">1. <a href="./common-auth-issues/">OAuth 認證失敗排查</a> <a class="header-anchor" href="#_1-oauth-認證失敗排查" aria-label="Permalink to &quot;1. [OAuth 認證失敗排查](./common-auth-issues/)&quot;">​</a></h3><p>解決 OAuth 認證、令牌刷新和帳戶相關常見問題。</p><ul><li>瀏覽器授權成功但終端提示「授權失敗」</li><li>突然報錯「Permission Denied」或「invalid_grant」</li><li>Safari 瀏覽器 OAuth 回調失敗</li><li>WSL2/Docker 環境下無法完成認證</li></ul><h3 id="_2-遷移帳戶" tabindex="-1">2. <a href="./migration-guide/">遷移帳戶</a> <a class="header-anchor" href="#_2-遷移帳戶" aria-label="Permalink to &quot;2. [遷移帳戶](./migration-guide/)&quot;">​</a></h3><p>在不同機器間遷移帳戶，處理版本升級。</p><ul><li>將帳戶從舊電腦遷移到新電腦</li><li>理解儲存格式的版本變化（v1/v2/v3）</li><li>解決遷移後的 invalid_grant 錯誤</li></ul><h3 id="_3-模型未找到排查" tabindex="-1">3. <a href="./model-not-found/">模型未找到排查</a> <a class="header-anchor" href="#_3-模型未找到排查" aria-label="Permalink to &quot;3. [模型未找到排查](./model-not-found/)&quot;">​</a></h3><p>解決模型未找到、400 錯誤等模型相關問題。</p><ul><li><code>Model not found</code> 錯誤排查</li><li><code>Invalid JSON payload received. Unknown name &quot;parameters&quot;</code> 400 錯誤</li><li>MCP 伺服器調用報錯</li></ul><h3 id="_4-插件相容性" tabindex="-1">4. <a href="./plugin-compatibility/">插件相容性</a> <a class="header-anchor" href="#_4-插件相容性" aria-label="Permalink to &quot;4. [插件相容性](./plugin-compatibility/)&quot;">​</a></h3><p>解決與 oh-my-opencode、DCP 等插件的相容性問題。</p><ul><li>正確配置插件載入順序</li><li>在 oh-my-opencode 中停用衝突的認證方式</li><li>為並行代理場景啟用 PID 偏移</li></ul><h3 id="_5-tos-警告" tabindex="-1">5. <a href="./tos-warning/">ToS 警告</a> <a class="header-anchor" href="#_5-tos-警告" aria-label="Permalink to &quot;5. [ToS 警告](./tos-warning/)&quot;">​</a></h3><p>理解使用風險，避免帳戶被封禁。</p><ul><li>了解 Google 服務條款限制</li><li>識別高風險場景（新帳戶、密集請求）</li><li>掌握避免帳戶封禁的最佳實踐</li></ul><h2 id="快速定位問題" tabindex="-1">快速定位問題 <a class="header-anchor" href="#快速定位問題" aria-label="Permalink to &quot;快速定位問題&quot;">​</a></h2><table tabindex="0"><thead><tr><th>錯誤現象</th><th>推薦閱讀</th></tr></thead><tbody><tr><td>認證失敗、授權超時</td><td><a href="./common-auth-issues/">OAuth 認證失敗排查</a></td></tr><tr><td>invalid_grant、Permission Denied</td><td><a href="./common-auth-issues/">OAuth 認證失敗排查</a></td></tr><tr><td>Model not found、400 錯誤</td><td><a href="./model-not-found/">模型未找到排查</a></td></tr><tr><td>與其他插件衝突</td><td><a href="./plugin-compatibility/">插件相容性</a></td></tr><tr><td>換新電腦、版本升級</td><td><a href="./migration-guide/">遷移帳戶</a></td></tr><tr><td>擔心帳戶安全</td><td><a href="./tos-warning/">ToS 警告</a></td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>解決問題後，你可以：</p><ul><li>📖 閱讀 <a href="./../advanced/">進階功能</a> 深入掌握多帳戶、會話恢復等特性</li><li>📚 查閱 <a href="./../appendix/">附錄</a> 了解架構設計和完整配置參考</li><li>🔄 關注 <a href="./../changelog/">更新日誌</a> 獲取最新功能和變更</li></ul>',26)])])}const f=t(o,[["render",r]]);export{p as __pageData,f as default};
